236	func evalTestName(item Item, target string, ctx Context) Entry {
237		e := Entry{AC: item.AC, Kind: KindTestName, Name: target}
238		if target == "" {
239			e.Result = ResultError
240			e.Evidence = "test-name AC could not resolve a test identifier"
241			return e
242		}
243		run := ctx.RunTest
244		if run == nil {
245			e.Result = ResultError
246			e.Evidence = "no test runner configured in context"
247			return e
248		}
249		ok, detail, err := run(target, ctx.Packages)
250		if err != nil {
251			e.Result = ResultError
252			e.Evidence = fmt.Sprintf("test runner error: %v", err)
253			return e
254		}
255		if ok {
256			e.Result = ResultPass
257			e.Evidence = fmt.Sprintf("test %s passed; %s", target, strings.TrimSpace(detail))
258			return e
259		}
260		e.Result = ResultFail
261		e.Evidence = fmt.Sprintf("test %s did not pass; %s", target, strings.TrimSpace(detail))
262		return e
263	}
