496	// checkpointPreDispatchDirt captures caller worktree changes as a commit on
497	// the current branch without using the caller checkout's real index or commit
498	// hooks. This keeps the execute-bead base semantics from FEAT-012 §22 while
499	// avoiding parent-checkout hook failures before the isolated worker worktree
500	// exists.
501	func checkpointPreDispatchDirt(projectRoot, attemptID string) (bool, error) {
502		if err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Run(); err != nil {
503			return false, nil
504		}
505		headOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").Output()
506		if err != nil {
507			return false, nil
508		}
509		head := strings.TrimSpace(string(headOut))
510		if head == "" {
511			return false, nil
512		}
513	
514		indexFile, err := os.CreateTemp("", "ddx-pre-dispatch-index-*")
515		if err != nil {
516			return false, fmt.Errorf("creating temp checkpoint index: %w", err)
517		}
518		indexPath := indexFile.Name()
519		_ = indexFile.Close()
520		_ = os.Remove(indexPath)
521		defer func() { _ = os.Remove(indexPath) }()
522	
523		gitWithIndex := func(args ...string) ([]byte, error) {
524			cmd := internalgit.Command(context.Background(), projectRoot, args...)
525			cmd.Env = append(cmd.Env, "GIT_INDEX_FILE="+indexPath)
526			return cmd.CombinedOutput()
527		}
528	
529		if out, err := gitWithIndex("read-tree", "HEAD"); err != nil {
530			return false, fmt.Errorf("initializing checkpoint index: %s: %w", strings.TrimSpace(string(out)), err)
531		}
532	
533		addArgs := []string{"add", "-A", "--", "."}
534		addArgs = append(addArgs, preDispatchCheckpointExcludePathspecs(projectRoot)...)
535		if out, err := gitWithIndex(addArgs...); err != nil {
536			return false, fmt.Errorf("staging checkpoint changes: %s: %w", strings.TrimSpace(string(out)), err)
537		}
538	
539		changedOut, err := gitWithIndex("diff", "--cached", "--name-only")
540		if err != nil {
541			return false, fmt.Errorf("checking checkpoint diff: %w", err)
542		}
543		if len(bytes.TrimSpace(changedOut)) == 0 {
544			return false, nil
545		}
546	
547		treeOut, err := gitWithIndex("write-tree")
548		if err != nil {
549			return false, fmt.Errorf("writing checkpoint tree: %s: %w", strings.TrimSpace(string(treeOut)), err)
550		}
551		tree := strings.TrimSpace(string(treeOut))
552		msg := "chore: checkpoint pre-execute-bead " + attemptID
553		commitOut, err := internalgit.Command(context.Background(), projectRoot,
554			"-c", "user.name=ddx-checkpoint",
555			"-c", "user.email=checkpoint@ddx.local",
556			"commit-tree", tree, "-p", head, "-m", msg,
557		).CombinedOutput()
558		if err != nil {
559			return false, fmt.Errorf("creating checkpoint commit: %s: %w", strings.TrimSpace(string(commitOut)), err)
560		}
561		commit := strings.TrimSpace(string(commitOut))
562	
563		refOut, _ := internalgit.Command(context.Background(), projectRoot, "symbolic-ref", "-q", "HEAD").Output()
564		ref := strings.TrimSpace(string(refOut))
565		if ref == "" {
566			ref = "HEAD"
567		}
568		if out, err := internalgit.Command(context.Background(), projectRoot, "update-ref", ref, commit, head).CombinedOutput(); err != nil {
569			return false, fmt.Errorf("advancing checkpoint ref: %s: %w", strings.TrimSpace(string(out)), err)
570		}
571		if out, err := internalgit.Command(context.Background(), projectRoot, "read-tree", "HEAD").CombinedOutput(); err != nil {
572			return false, fmt.Errorf("syncing checkpoint index: %s: %w", strings.TrimSpace(string(out)), err)
573		}
574		return true, nil
575	}
