38	// ErrReviewVerdictUnparseable is the sentinel returned by ParseReviewVerdict
39	// when the reviewer output cannot be decoded into a valid ReviewVerdict.
40	// The execute-loop classifies it as evidence.OutcomeReviewUnparseable
41	// (retryable review-error) rather than mis-recording a BLOCK verdict.
42	var ErrReviewVerdictUnparseable = errors.New("reviewer output: unparseable JSON verdict")
43	
44	// ParseReviewVerdict decodes a reviewer agent's raw output into a
45	// ReviewVerdict. It accepts:
46	//   - raw JSON object;
47	//   - a single ```json …``` fenced block;
48	//   - mixed prose and fenced blocks where the LAST ```json block is the
49	//     verdict.
50	//
51	// It rejects:
52	//   - empty input;
53	//   - inputs containing no JSON object at all;
54	//   - JSON missing the "verdict" field;
55	//   - unknown verdict values (anything other than APPROVE,
56	//     REQUEST_CHANGES, BLOCK);
57	//   - truncated/malformed JSON.
58	//
59	// Unknown fields outside the schema are tolerated (forward-compat).
60	func ParseReviewVerdict(raw []byte) (ReviewVerdict, error) {
61		if len(strings.TrimSpace(string(raw))) == 0 {
62			return ReviewVerdict{}, fmt.Errorf("%w: empty input", ErrReviewVerdictUnparseable)
63		}
64		candidate, ok := extractJSONCandidate(string(raw))
65		if !ok {
66			return ReviewVerdict{}, fmt.Errorf("%w: no JSON object found", ErrReviewVerdictUnparseable)
67		}
68	
