// allFailsWaived reports whether every failing AC item in acOut is covered by
// an ac_waive.txt entry (format: "#N reason") in executionDir. Returns true
// when there are no failures.
func allFailsWaived(acOut *accheck.Output, executionDir string) bool {
	if acOut == nil || acOut.Summary.Fail == 0 {
		return true
	}
	waived := readWaiveSet(executionDir)
	for _, entry := range acOut.Items {
		if entry.Result == accheck.ResultFail && !waived[entry.AC] {
			return false
		}
	}
	return true
}

// readWaiveSet parses ac_waive.txt in executionDir and returns the set of
// waived AC numbers. Lines must match "#N ..." where N is the 1-based AC
// index.
func readWaiveSet(executionDir string) map[int]bool {
	data, err := os.ReadFile(filepath.Join(executionDir, "ac_waive.txt"))
	if err != nil {
		return nil
	}
	set := make(map[int]bool)
	for _, line := range strings.Split(string(data), "\n") {
		line = strings.TrimSpace(line)
		if !strings.HasPrefix(line, "#") {
			continue
		}
		var n int
		if _, scanErr := fmt.Sscanf(line[1:], "%d", &n); scanErr == nil && n > 0 {
			set[n] = true
		}
	}
	return set
}

// buildACWaiveTrailers returns "AC-Waive: #N <reason>" lines for each failing
// AC covered by ac_waive.txt. Returns "" when no waive entries apply.
func buildACWaiveTrailers(acOut *accheck.Output, executionDir string) string {
	if acOut == nil || acOut.Summary.Fail == 0 {
		return ""
	}
	data, err := os.ReadFile(filepath.Join(executionDir, "ac_waive.txt"))
	if err != nil || len(data) == 0 {
		return ""
	}
	var trailers []string
	for _, entry := range acOut.Items {
		if entry.Result != accheck.ResultFail {
			continue
		}
		prefix := fmt.Sprintf("#%d", entry.AC)
		for _, line := range strings.Split(string(data), "\n") {
			trimmed := strings.TrimSpace(line)
			if strings.HasPrefix(trimmed, prefix) {
				trailers = append(trailers, "AC-Waive: "+trimmed)
				break
			}
		}
	}
	return strings.Join(trailers, "\n")
}

