// TestReviewer_RequestClarification_NotBlockingQueue verifies that a
// REQUEST_CLARIFICATION verdict routes the bead to status=proposed (operator
// lane) without blocking the drain queue, and that the correct event is emitted.
func TestReviewer_RequestClarification_NotBlockingQueue(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	reviewer := beadReviewerFunc(func(_ context.Context, _, _ string, _ ImplementerRouting) (*ReviewResult, error) {
		return &ReviewResult{
			Verdict:         VerdictRequestClarification,
			Rationale:       "cannot adjudicate AC#1 without more context",
			ReviewerHarness: "claude",
			ReviewerModel:   "claude-opus-4-6",
		}, nil
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	out := RunPostMergeReview(context.Background(), PostMergeReviewInput{
		Bead: *first,
		Report: ExecuteBeadReport{
			BeadID:    first.ID,
			Status:    ExecuteBeadStatusSuccess,
			SessionID: "sess-rc-1",
			ResultRev: "cafecafe",
			BaseRev:   "deadbeef",
		},
		Reviewer:    reviewer,
		Store:       store,
		ProjectRoot: t.TempDir(),
		Rcfg:        rcfg,
		Now:         time.Now,
		Assignee:    "worker",
	})

	require.False(t, out.Approved)
	assert.Equal(t, ExecuteBeadStatusReviewRequestClarification, out.Report.Status)

	// Bead must move to proposed for operator attention.
	got, err := store.Get(first.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusProposed, got.Status, "REQUEST_CLARIFICATION must park bead to proposed")
	assert.NotEqual(t, bead.StatusClosed, got.Status)

	// review-request-clarification event must be appended.
	events, err := store.Events(first.ID)
	require.NoError(t, err)
	found := false
	for _, ev := range events {
		if ev.Kind == ReviewRequestClarificationEventKind {
			found = true
			assert.Contains(t, ev.Body, "result_rev=cafecafe")
		}
	}
	assert.True(t, found, "review-request-clarification event must be appended")

	// Must not consume no-progress budget.
	assert.False(t, isValidImplementationAttempt(ExecuteBeadReport{
		Status:    ExecuteBeadStatusReviewRequestClarification,
		BaseRev:   "deadbeef",
		ResultRev: "cafecafe",
	}))
}

