// TestReviewer_RegressionFakeRetainDays_BlocksByACCheck is a regression test
// verifying that a BLOCK verdict driven by ac-check evidence (e.g. a fake-work
// pattern where the agent retained file contents without changes) is processed
// correctly through the post-merge review state machine.
func TestReviewer_RegressionFakeRetainDays_BlocksByACCheck(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	acJSON := `{"schema_version":1,"bead_id":"ddx-test","summary":{"pass":0,"fail":2,"needs_judgment":0},"items":[{"ac":1,"kind":"test-name","result":"fail","evidence":"TestRetainDays: not found"},{"ac":2,"kind":"symbol","result":"fail","evidence":"RetainDays: symbol absent"}]}`
	reviewer := beadReviewerFunc(func(_ context.Context, beadID, _ string, impl ImplementerRouting) (*ReviewResult, error) {
		return &ReviewResult{
			Verdict:         VerdictBlock,
			Rationale:       "ac-check: 2 fail(s); TestRetainDays not present; symbol absent",
			ReviewerHarness: "claude",
			ReviewerModel:   "claude-opus-4-6",
			Findings: []Finding{
				{Severity: "block", Summary: "TestRetainDays not implemented", Location: "cli/internal/foo_test.go"},
				{Severity: "block", Summary: "RetainDays symbol absent", Location: "cli/internal/foo.go"},
			},
		}, nil
	})
	// Write ac-check.json for the attempt so readACCheckJSON can find it.
	attemptID := "attempt-fake-retain"
	acDir := filepath.Join(t.TempDir(), ".ddx", "executions", attemptID)
	require.NoError(t, os.MkdirAll(acDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(acDir, "ac-check.json"), []byte(acJSON), 0o644))

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	out := RunPostMergeReview(context.Background(), PostMergeReviewInput{
		Bead: *first,
		Report: ExecuteBeadReport{
			BeadID:    first.ID,
			AttemptID: attemptID,
			Status:    ExecuteBeadStatusSuccess,
			SessionID: "sess-fake-retain",
			ResultRev: "fakereta1",
			BaseRev:   "fakereta0",
		},
		Reviewer:    reviewer,
		Store:       store,
		ProjectRoot: t.TempDir(),
		Rcfg:        rcfg,
		Now:         time.Now,
		Assignee:    "worker",
	})

	require.False(t, out.Approved, "BLOCK from ac-check evidence must not approve the bead")
	assert.NotEqual(t, bead.StatusClosed, func() bead.Status {
		got, _ := store.Get(first.ID)
		return got.Status
	}(), "fake-work BLOCK must not close the bead")
	events, err := store.Events(first.ID)
	require.NoError(t, err)
	found := false
	for _, ev := range events {
		if ev.Kind == "review" && ev.Summary == "BLOCK" {
			found = true
		}
	}
	assert.True(t, found, "BLOCK event must be appended for fake-work regression")
}

