// readACCheckJSON reads .ddx/executions/<attemptID>/ac-check.json and returns
// its trimmed content. Returns "" when attemptID is empty or the file is absent
// so the reviewer prompt proceeds without the <ac-check> section.
func readACCheckJSON(projectRoot, attemptID string) string {
	if projectRoot == "" || attemptID == "" {
		return ""
	}
	p := filepath.Join(projectRoot, ".ddx", "executions", attemptID, "ac-check.json")
	// evidence:allow-unbounded reason="ac-check.json is machine-generated output bounded by AC item count; not user-supplied evidence"
	data, err := os.ReadFile(p)
	if err != nil {
		return ""
	}
	return strings.TrimSpace(string(data))
}

